// Adapters
// The order:status-changed handler sends event.order.userId as the recipient,
// so the email adapter needs a resolver to map user IDs to email addresses.
const emailAdapter = new EmailAdapter({
  resolveRecipient: (recipient: string) => {
    // If it's already an email, return it
    if (recipient.includes('@')) return recipient;
    // Map user IDs to emails
    const emailBook: Record<string, string> = {
      'user-1': 'alice@example.com',
      'user-2': 'bob@example.com',
      'user-alice': 'alice@example.com',
      'user-bob': 'bob@example.com',
      'user-42': 'test@example.com',
    };
    return emailBook[recipient] ?? null;
  },
});

