+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function orderCreatedEvent(user: User, order: Order): OrderCreatedEvent {
+  return { type: 'order:created', order, user, timestamp: new Date() };
+}
+
+function orderStatusChangedEvent(
+  order: Order,
+  previousStatus: string,
+  newStatus: string,
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order,
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
+
+// --- Full pipeline setup helper ---
+
+interface Pipeline {
+  eventBus: EventBus;
+  notificationService: NotificationService;
+  emailAdapter: EmailAdapter;
+  smsAdapter: SmsAdapter;
+  webhookAdapter: WebhookAdapter;
+  preferencesService: PreferencesService;
+  historyService: NotificationHistoryService;
+  db: Database;
+}
+
+function buildPipeline(): Pipeline {
+  const db = new Database();
+  const eventBus = new EventBus();
+
+  // Adapters
+  // The order:status-changed handler sends event.order.userId as the recipient,
+  // so the email adapter needs a resolver to map user IDs to email addresses.
+  const emailAdapter = new EmailAdapter({
+    resolveRecipient: (recipient: string) => {
+      // If it's already an email, return it
+      if (recipient.includes('@')) return recipient;
+      // Map user IDs to emails
+      const emailBook: Record<string, string> = {
+        'user-1': 'alice@example.com',
+        'user-2': 'bob@example.com',
+        'user-alice': 'alice@example.com',
+        'user-bob': 'bob@example.com',
+        'user-42': 'test@example.com',
+      };
+      return emailBook[recipient] ?? null;
+    },
+  });
+  const smsAdapter = new SmsAdapter({
+    resolveRecipient: (recipient: string) => {
+      // Map user IDs and emails to phone numbers for testing
+      const phoneBook: Record<string, string> = {
+        'user-1': '+15551234567',
+        'user-2': '+15559876543',
+        'alice@example.com': '+15551234567',
+        'bob@example.com': '+15559876543',
+      };
+      return phoneBook[recipient] ?? null;
+    },
+  });
+  const webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
+
+  // Services
+  const preferencesRepo = new PreferencesRepository(db);
+  const preferencesService = new PreferencesService(preferencesRepo);
+
+  const logRepo = new NotificationLogRepository(db);
+  const historyService = new NotificationHistoryService(logRepo);
+
+  // Wire up notification service
+  const notificationService = new NotificationService(eventBus);
+  notificationService.registerAdapter(emailAdapter);
+  notificationService.registerAdapter(smsAdapter);
+  notificationService.registerAdapter(webhookAdapter);
+  notificationService.setPreferencesService(preferencesService);
+  notificationService.setHistoryService(historyService);
+
+  return {
+    eventBus,
+    notificationService,
+    emailAdapter,
+    smsAdapter,
+    webhookAdapter,
+    preferencesService,
+    historyService,
+    db,
+  };
+}
